func newAuthRefreshCmd(flags *rootFlags) *cobra.Command {
	var waitTimeout time.Duration
	cmd := &cobra.Command{
		Use:     "refresh",
		Short:   "Refresh the browser session",
		Example: "  erank-pp-cli auth refresh",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			w := cmd.OutOrStdout()
			targetURL := browserSessionTargetURL(cfg)
			label, openErr := openBrowserForCookieRefresh(targetURL)
			if openErr != nil {
				fmt.Fprintf(w, "Could not open a browser automatically (%v).\n", openErr)
				fmt.Fprintf(w, "Open this URL in Chrome, complete login or browser challenge, then continue:\n  %s\n", targetURL)
			} else {
				fmt.Fprintf(w, "Opened %s with %s.\n", targetURL, label)
			}
			waitForCookieRefreshBrowser(cmd, flags, targetURL, w)

			if err := refreshStoredBrowserCookies(cfg, w); err != nil {
				return authErr(err)
			}

			fmt.Fprintf(w, "Validating browser session...")
			if err := validateAndWriteBrowserSessionProofWithRetry(cmd.Context(), cfg, flags, waitTimeout); err != nil {
				fmt.Fprintf(w, " %s\n", red("failed"))
				return authErr(fmt.Errorf("browser session validation failed: %w", err))
			}
			fmt.Fprintf(w, " %s\n", green("valid"))
			fmt.Fprintf(w, "Browser session proof refreshed at %s\n", browserSessionProofPath(cfg))
			return nil
		},
	}
	cmd.Flags().DurationVar(&waitTimeout, "wait-timeout", 90*time.Second, "How long to wait for login or browser challenge clearance")
	return cmd
}

func browserSessionTargetURL(cfg *config.Config) string {
	baseURL := strings.TrimRight("https://members.erank.com", "/")
	if cfg != nil && cfg.BaseURL != "" {
		baseURL = strings.TrimRight(cfg.BaseURL, "/")
	}
	validationPath := strings.TrimSpace("/api/keyword-tool/stats?keyword=dad+mug&country=USA&marketplace=etsy")
	if validationPath == "" {
		return baseURL
	}
	if strings.HasPrefix(validationPath, "http://") || strings.HasPrefix(validationPath, "https://") {
		return validationPath
	}
	return baseURL + "/" + strings.TrimLeft(validationPath, "/")
}

type browserCaptureHandle struct {
	Tool      string
	Label     string
	EvalArgs  []string
	CloseArgs []string
}

var errBrowserCaptureRequired = errors.New("browser capture tool required")

func openBrowserCaptureSession(targetURL string) (browserCaptureHandle, error) {
	if _, err := exec.LookPath("browser-use"); err == nil {
		baseArgs := []string{"--session", browserCaptureSessionName(), "--headed"}
		closeArgs := append(append([]string{}, baseArgs...), "close")
		label := "browser-use session " + browserCaptureSessionName()
		openArgs := append(append([]string{}, baseArgs...), "open", targetURL)
		if err := runBrowserUseOpenWithRetry(openArgs, closeArgs); err != nil {
			return browserCaptureHandle{}, err
		}
		return browserCaptureHandle{Tool: "browser-use", Label: label, EvalArgs: baseArgs, CloseArgs: closeArgs}, nil
	}
	if _, err := exec.LookPath("agent-browser"); err == nil {
		baseArgs := []string{"--session", browserCaptureSessionName()}
		openArgs := append(append([]string{}, baseArgs...), "--headed", "open", targetURL)
		if err := runBrowserCaptureCommand("agent-browser", openArgs...); err != nil {
			return browserCaptureHandle{}, err
		}
		closeArgs := append(append([]string{}, baseArgs...), "close")
		return browserCaptureHandle{Tool: "agent-browser", Label: "agent-browser session " + browserCaptureSessionName(), EvalArgs: baseArgs, CloseArgs: closeArgs}, nil
	}
	return browserCaptureHandle{}, errBrowserCaptureRequired
}

func browserCaptureSessionName() string {
	return "erank-pp-cli"
}

func runBrowserUseOpenWithRetry(openArgs []string, closeArgs []string) error {
	out, err := exec.Command("browser-use", openArgs...).CombinedOutput()
	if err == nil {
		return nil
	}
	if !browserUseSessionConfigMismatch(out) || len(closeArgs) == 0 {
		return browserCaptureCommandError("browser-use", openArgs, err, out)
	}
	if closeOut, closeErr := exec.Command("browser-use", closeArgs...).CombinedOutput(); closeErr != nil {
		return fmt.Errorf("browser-use stale session close: %w: %s", closeErr, strings.TrimSpace(string(closeOut)))
	}
	retryOut, retryErr := exec.Command("browser-use", openArgs...).CombinedOutput()
	if retryErr != nil {
		return browserCaptureCommandError("browser-use", openArgs, retryErr, retryOut)
	}
	return nil
}

func runBrowserCaptureCommand(tool string, args ...string) error {
	out, err := exec.Command(tool, args...).CombinedOutput()
	if err != nil {
		return browserCaptureCommandError(tool, args, err, out)
	}
	return nil
}

func browserCaptureCommandError(tool string, args []string, err error, out []byte) error {
	detail := strings.TrimSpace(string(out))
	action := strings.Join(args, " ")
	if detail == "" {
		return fmt.Errorf("%s %s: %w", tool, action, err)
	}
	return fmt.Errorf("%s %s: %w: %s", tool, action, err, detail)
}

func browserUseSessionConfigMismatch(out []byte) bool {
	text := strings.ToLower(string(out))
	return strings.Contains(text, "already running with different config")
}

func evalBrowserCapture(capture browserCaptureHandle, script string) ([]byte, error) {
	args := append(append([]string{}, capture.EvalArgs...), "eval", script)
	out, err := exec.Command(capture.Tool, args...).CombinedOutput()
	if err != nil {
		return nil, fmt.Errorf("%s eval: %w: %s", capture.Tool, err, strings.TrimSpace(string(out)))
	}
	return out, nil
}

func closeBrowserCaptureSession(capture browserCaptureHandle, w io.Writer) error {
	if len(capture.CloseArgs) > 0 {
		if err := exec.Command(capture.Tool, capture.CloseArgs...).Run(); err != nil {
			fmt.Fprintf(w, "Could not close %s session (%v).\n", capture.Tool, err)
			return fmt.Errorf("closing %s session: %w", capture.Tool, err)
		}
		fmt.Fprintf(w, "Closed %s session.\n", capture.Tool)
		return nil
	}
	return nil
}
func openBrowserForCookieRefresh(targetURL string) (string, error) {
	switch runtime.GOOS {
	case "darwin":
		if err := exec.Command("open", "-a", "Google Chrome", targetURL).Run(); err == nil {
			return "Google Chrome", nil
		}
		if err := exec.Command("open", targetURL).Run(); err == nil {
			return "default browser", nil
		}
	case "windows":
		if browser, ok := findBrowserExecutable([]string{"chrome.exe", "msedge.exe"}); ok {
			if err := exec.Command(browser, targetURL).Start(); err == nil {
				return filepath.Base(browser), nil
			}
		}
		if err := exec.Command("rundll32", "url.dll,FileProtocolHandler", targetURL).Start(); err == nil {
			return "default browser", nil
		}
	default:
		if browser, ok := findBrowserExecutable([]string{"google-chrome", "google-chrome-stable", "chromium", "chromium-browser", "microsoft-edge"}); ok {
			if err := exec.Command(browser, targetURL).Start(); err == nil {
				return filepath.Base(browser), nil
			}
		}
		if err := exec.Command("xdg-open", targetURL).Start(); err == nil {
			return "default browser", nil
		}
	}
	return "", fmt.Errorf("no browser launcher found")
}

func findBrowserExecutable(names []string) (string, bool) {
	for _, name := range names {
		if path, err := exec.LookPath(name); err == nil {
			return path, true
		}
	}
	return "", false
}

func waitForCookieRefreshBrowser(cmd *cobra.Command, flags *rootFlags, targetURL string, w io.Writer) {
	interactive := !flags.yes && !flags.noInput && isTerminal(w)
	if !interactive {
		fmt.Fprintf(w, "Attempting to read browser cookies now. If validation fails, rerun interactively after clearing %s in Chrome.\n", targetURL)
		return
	}
	fmt.Fprint(w, "Complete any login or browser challenge in Chrome, then press Enter to continue.")
	scanner := bufio.NewScanner(cmd.InOrStdin())
	scanner.Scan()
	fmt.Fprintln(w)
}
func refreshStoredBrowserCookies(cfg *config.Config, w io.Writer) error {
	domain := "members.erank.com"
	if domain == "" {
		return fmt.Errorf("no cookie domain configured")
	}

	cookies, err := extractLiveCookies(domain)
	if err != nil || cookies == "" {
		tool, toolErr := detectCookieTool()
		if toolErr != nil {
			if err != nil {
				return fmt.Errorf("reading live browser cookies: %w", err)
			}
			return toolErr
		}
		cookies, err = extractCookies(tool, domain, "")
		if err != nil {
			return fmt.Errorf("extracting cookies: %w", err)
		}
	}
	if cookies == "" {
		return fmt.Errorf("no cookies found for %s", domain)
	}
	cookieMap := parseCookieString(cookies)
	requiredCookies := []string{"er_sess_x", "sid_er", "XSRF-TOKEN"}
	for _, name := range requiredCookies {
		if _, ok := cookieMap[name]; !ok {
			return fmt.Errorf("cookie %q not found for %s", name, domain)
		}
	}
	composed := "{XSRF-TOKEN}"
	for _, name := range requiredCookies {
		composed = strings.ReplaceAll(composed, "{"+name+"}", cookieMap[name])
	}
	if err := cfg.SaveTokens("", "", composed, "", time.Time{}); err != nil {
		return configErr(fmt.Errorf("saving auth: %w", err))
	}
	// Refresh path mirrors login: persist required cookies so the next
	// client construction's LoadCookieJar() pickup carries the user's
	// session, not just the static auth header.
	jarCookies := make(map[string]string, len(requiredCookies))
	for _, name := range requiredCookies {
		if v, ok := cookieMap[name]; ok {
			jarCookies[name] = v
		}
	}
	if err := client.WriteCookieJarFromMap(domain, jarCookies); err != nil {
		fmt.Fprintf(w, "warning: persisting cookie jar: %v (auth header still saved)\n", err)
	}
	fmt.Fprintf(w, "Updated stored browser auth from %d cookies.\n", len(requiredCookies))
	return nil
}
func cookieToolSupportsProfiles(tool string) bool {
	switch tool {
	case "pycookiecheat", "pycookiecheat-cli", "cookie-scoop":
		return true
	default:
		return false
	}
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "status",
		Short:   "Show authentication status",
		Example: "  erank-pp-cli auth status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			w := cmd.OutOrStdout()
			header := cfg.AuthHeader()
			if header == "" {
				if v := os.Getenv("ERANK_XSRF_TOKEN"); v != "" {
					fmt.Fprintln(w, green("Authenticated"))
					fmt.Fprintf(w, "  Source: %s env var\n", "ERANK_XSRF_TOKEN")
					return nil
				}
				fmt.Fprintln(w, red("Not authenticated"))
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, "Log in from your browser session:")
				fmt.Fprintf(w, "  erank-pp-cli auth login --chrome\n")
				return authErr(fmt.Errorf("no credentials configured"))
			}

			fmt.Fprintln(w, green("Authenticated"))
			fmt.Fprintf(w, "  Source: %s\n", cfg.AuthSource)
			fmt.Fprintf(w, "  Domain: members.erank.com\n")
			fmt.Fprintf(w, "  Config: %s\n", cfg.Path)
			return nil
		},
	}
}

// newAuthSetTokenCmd is the escape hatch for sites whose access token can't
// be reached by the cookie-jar extractor in `auth login --chrome` — most
// commonly Auth0 SPA SDK v2+ deployments using the default in-memory cache,
// where the JWT lives in JS heap and never touches cookies or localStorage.
// Users (or agents) grab the bearer from DevTools → Network → Authorization
// and paste it here instead of hand-editing config.toml.
//
// The cliutil.LooksLikeJWT length floor is the cookie-vs-JWT-shape gate from
// retro #1598 WU-2: short tracking cookies like Cloudflare's `__cf_bm`
// (~31 chars) happen to have three base64url segments and would otherwise
// silently land as the access token.
func newAuthSetTokenCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "set-token <jwt>",
		Short:   "Save a bearer JWT pasted from DevTools (escape hatch for in-memory tokens)",
		Example: "  erank-pp-cli auth set-token eyJhbGciOi...",
		Long: "Save a bearer JWT pasted from DevTools (escape hatch for in-memory tokens).\n\n" +
			"Use this when `auth login --chrome` can't reach the access token — most\n" +
			"commonly Auth0 SPA SDK deployments that keep the JWT in JS heap memory.\n" +
			"Open DevTools → Network → any authenticated request → copy the\n" +
			"`Authorization: Bearer ...` value and paste the JWT portion here.\n\n" +
			"The token is validated for JWT shape (three base64url segments, length\n" +
			"floor) so short tracking cookies don't get saved as credentials.",
		Args: cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			token := strings.TrimSpace(args[0])
			token = strings.TrimPrefix(token, "Bearer ")
			if !cliutil.LooksLikeJWT(token) {
				return authErr(fmt.Errorf("argument is not JWT-shaped (three base64url segments, ≥150 chars total). " +
					"This is the cookie-vs-JWT-shape gate — short tracking cookies like Cloudflare's __cf_bm " +
					"share the segment shape but aren't credentials. Paste the `Authorization: Bearer ...` value " +
					"from DevTools → Network, not a cookie jar"))
			}

			// Clear any legacy auth_header so AuthHeader() falls through to
			// the newly-saved bearer. Mirrors auth_simple's set-token.
			cfg.AuthHeaderVal = ""
			// Pass a zero expiry. We can't decode the JWT to learn its real
			// lifetime, and preserving a stale cfg.TokenExpiry from a prior
			// session (the exact case escape-hatch users reach this from)
			// would later mislead any expiry-aware status check into treating
			// this fresh token as already expired. Actual expiry surfaces via
			// 401 on the next API call, same as the rest of the browser-auth
			// flow. Matches ClearTokens / SaveBearerToken's zero-on-write
			// invariant in config.go.tmpl.
			if err := cfg.SaveTokens("", "", token, "", time.Time{}); err != nil {
				return configErr(fmt.Errorf("saving token: %w", err))
			}

			// JSON envelope: {saved, config_path}.
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Token saved to %s\n", cfg.Path)
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "logout",
		Short:   "Clear stored credentials",
		Example: "  erank-pp-cli auth logout",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			if err := cfg.ClearTokens(); err != nil {
				return configErr(fmt.Errorf("clearing tokens: %w", err))
			}
			if err := clearBrowserSessionProof(cfg); err != nil {
				return configErr(fmt.Errorf("clearing browser-session proof: %w", err))
			}
			if os.Getenv("ERANK_XSRF_TOKEN") != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Config cleared. Note: %s env var is still set.\n", "ERANK_XSRF_TOKEN")
				return nil
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Credentials cleared.")
			return nil
		},
	}
}

// --- Chrome profile discovery ---
// chromeDataDir returns the Chrome user data directory for the current OS.
func chromeDataDir() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", err
	}

	switch runtime.GOOS {
	case "darwin":
		return filepath.Join(home, "Library", "Application Support", "Google", "Chrome"), nil
	case "linux":
		return filepath.Join(home, ".config", "google-chrome"), nil
	case "windows":
		localAppData := os.Getenv("LOCALAPPDATA")
		if localAppData == "" {
			localAppData = filepath.Join(home, "AppData", "Local")
		}
		return filepath.Join(localAppData, "Google", "Chrome", "User Data"), nil
	default:
		return "", fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
}

// discoverChromeProfiles finds Chrome profiles and counts cookies matching the domain.
func discoverChromeProfiles(domain string, requiredCookies []string) ([]chromeProfile, error) {
	dataDir, err := chromeDataDir()
	if err != nil {
		return nil, err
	}
	if _, err := exec.LookPath("sqlite3"); err != nil {
		return nil, fmt.Errorf("sqlite3 not found")
	}

	entries, err := os.ReadDir(dataDir)
	if err != nil {
		return nil, fmt.Errorf("cannot read Chrome data directory: %w", err)
	}

	// Match domain for SQLite query — host_key uses leading dot (e.g. ".notion.so")
	domainPattern := "%" + strings.TrimPrefix(domain, ".") + "%"

	var profiles []chromeProfile
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		name := entry.Name()
		if name != "Default" && !strings.HasPrefix(name, "Profile ") {
			continue
		}

		profilePath := filepath.Join(dataDir, name)
		cookiesDB := filepath.Join(profilePath, "Cookies")
		if _, err := os.Stat(cookiesDB); err != nil {
			continue
		}

		displayName := readProfileDisplayName(filepath.Join(profilePath, "Preferences"))
		if displayName == "" {
			displayName = name
		}

		inspection := inspectCookiesForDomain(cookiesDB, domainPattern, requiredCookies)

		profiles = append(profiles, chromeProfile{
			Dir:                 name,
			DisplayName:         displayName,
			CookieCount:         inspection.Count,
			RequiredCookieCount: inspection.RequiredCookieCount,
			MissingCookies:      inspection.MissingCookies,
		})
	}

	// Sort: profiles with required auth cookies first, then with the most
	// target-domain cookies, then by directory name for determinism.
	sort.Slice(profiles, func(i, j int) bool {
		if profiles[i].RequiredCookieCount != profiles[j].RequiredCookieCount {
			return profiles[i].RequiredCookieCount > profiles[j].RequiredCookieCount
		}
		if profiles[i].CookieCount != profiles[j].CookieCount {
			return profiles[i].CookieCount > profiles[j].CookieCount
		}
		return profiles[i].Dir < profiles[j].Dir
	})

	return profiles, nil
}

// readProfileDisplayName extracts the human-readable name from Chrome's Preferences JSON.
func readProfileDisplayName(prefsPath string) string {
	data, err := os.ReadFile(prefsPath)
	if err != nil {
		return ""
	}
	var prefs struct {
		Profile struct {
			Name string `json:"name"`
		} `json:"profile"`
	}
	if err := json.Unmarshal(data, &prefs); err != nil {
		return ""
	}
	return prefs.Profile.Name
}

type chromeCookieInspection struct {
	Count               int
	RequiredCookieCount int
	MissingCookies      []string
}

func inspectCookiesForDomain(cookiesDB, domainPattern string, requiredCookies []string) chromeCookieInspection {
	result := chromeCookieInspection{Count: countCookiesForDomain(cookiesDB, domainPattern)}
	if len(requiredCookies) == 0 {
		return result
	}

	missing := make(map[string]bool, len(requiredCookies))
	for _, name := range requiredCookies {
		missing[name] = true
	}

	tmpFile, err := os.CreateTemp("", "cookies-probe-*.db")
	if err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	tmpPath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(tmpPath)
	defer os.Remove(tmpPath + "-wal")
	defer os.Remove(tmpPath + "-shm")

	if err := copyFileIfExists(cookiesDB, tmpPath); err != nil {
		result.MissingCookies = requiredCookies
		return result
	}
	_ = copyFileIfExists(cookiesDB+"-wal", tmpPath+"-wal")
	_ = copyFileIfExists(cookiesDB+"-shm", tmpPath+"-shm")

	quotedNames := make([]string, 0, len(requiredCookies))
	for _, name := range requiredCookies {
		quotedNames = append(quotedNames, sqlQuoteLiteral(name))
	}
	query := fmt.Sprintf("SELECT DISTINCT name FROM cookies WHERE host_key LIKE %s AND name IN (%s)", sqlQuoteLiteral(domainPattern), strings.Join(quotedNames, ","))
	out, err := exec.Command("sqlite3", tmpPath, query).Output()
	if err != nil {
		result.MissingCookies = requiredCookies
		return result
	}

	for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
		name := strings.TrimSpace(line)
		if missing[name] {
			delete(missing, name)
			result.RequiredCookieCount++
		}
	}
	for _, name := range requiredCookies {
		if missing[name] {
			result.MissingCookies = append(result.MissingCookies, name)
		}
	}
	return result
}

func sqlQuoteLiteral(s string) string {
	return "'" + strings.ReplaceAll(s, "'", "''") + "'"
}

// countCookiesForDomain copies the Cookies DB (plus WAL/SHM) to temp and counts matching rows.
// Uses sqlite3 when available; host_key is plaintext so no decryption is needed.
func countCookiesForDomain(cookiesDB, domainPattern string) int {
	tmpFile, err := os.CreateTemp("", "cookies-probe-*.db")
	if err != nil {
		return 0
	}
	tmpPath := tmpFile.Name()
	tmpFile.Close()
	defer os.Remove(tmpPath)
	defer os.Remove(tmpPath + "-wal")
	defer os.Remove(tmpPath + "-shm")

	// Copy the database file plus WAL/SHM to avoid Chrome's WAL lock
	// and to include uncommitted cookie writes that are still in the WAL.
	if err := copyFileIfExists(cookiesDB, tmpPath); err != nil {
		return 0
	}
	_ = copyFileIfExists(cookiesDB+"-wal", tmpPath+"-wal")
	_ = copyFileIfExists(cookiesDB+"-shm", tmpPath+"-shm")

	query := fmt.Sprintf("SELECT COUNT(*) FROM cookies WHERE host_key LIKE '%s'", domainPattern)
	out, err := exec.Command("sqlite3", tmpPath, query).Output()
	if err != nil {
		return 0
	}

	count := 0
	fmt.Sscanf(strings.TrimSpace(string(out)), "%d", &count)
	return count
}

// copyFileIfExists copies src to dst. Returns nil if src does not exist.
func copyFileIfExists(src, dst string) error {
	in, err := os.Open(src)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	defer in.Close()
	out, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer out.Close()
	_, err = io.Copy(out, in)
	return err
}

// resolveChromeProfile determines which Chrome profile to read cookies from.
// Priority: --profile flag > auto-detect (single match) > interactive prompt.
func resolveChromeProfile(w io.Writer, r io.Reader, domain, profileFlag string, requiredCookies []string) (string, error) {
	if profileFlag != "" {
		return resolveProfileByName(profileFlag)
	}

	profiles, err := discoverChromeProfiles(domain, requiredCookies)
	if err != nil {
		// Profile probing is optional; cookie extraction can still succeed without it.
		fmt.Fprintf(w, "Could not inspect Chrome profiles (%v); continuing without auto-detection.\n", err)
		return "", nil
	}

	// Prefer profiles that contain every required auth cookie. If the CLI does
	// not know specific cookie names, fall back to any target-domain cookie.
	var withRequired []chromeProfile
	var withCookies []chromeProfile
	for _, p := range profiles {
		if len(requiredCookies) > 0 && p.RequiredCookieCount == len(requiredCookies) {
			withRequired = append(withRequired, p)
		}
		if p.CookieCount > 0 {
			withCookies = append(withCookies, p)
		}
	}

	if len(withRequired) > 0 {
		return chooseChromeProfile(w, r, withRequired, domain, true)
	}
	if len(requiredCookies) > 0 {
		printMissingCookieHint(w, profiles, requiredCookies)
	}
	if len(withCookies) > 0 {
		return chooseChromeProfile(w, r, withCookies, domain, false)
	}
	return "", fmt.Errorf("no Chrome profile has cookies for %s", domain)
}

func printMissingCookieHint(w io.Writer, profiles []chromeProfile, requiredCookies []string) {
	if len(requiredCookies) == 0 {
		return
	}
	for _, p := range profiles {
		if p.CookieCount == 0 || len(p.MissingCookies) == 0 {
			continue
		}
		fmt.Fprintf(w, "Chrome profile %s (%s) is missing required cookies: %s\n", p.DisplayName, p.Dir, strings.Join(p.MissingCookies, ", "))
		return
	}
}

func chooseChromeProfile(w io.Writer, r io.Reader, profiles []chromeProfile, domain string, required bool) (string, error) {
	label := "cookies"
	if required {
		label = "required cookies"
	}

	switch len(profiles) {
	case 1:
		fmt.Fprintf(w, "Auto-detected Chrome profile: %s (%s, %d %s)\n", profiles[0].DisplayName, profiles[0].Dir, profileCookieCount(profiles[0], required), label)
		return profiles[0].Dir, nil
	default:
		// Multiple profiles have matching cookies. Non-interactive runs pick the
		// strongest match; terminals get an explicit choice.
		if !isTerminal(w) {
			selected := profiles[0]
			fmt.Fprintf(w, "Auto-selected Chrome profile: %s (%s, %d %s)\n", selected.DisplayName, selected.Dir, profileCookieCount(selected, required), label)
			fmt.Fprintf(w, "Use --profile to select a different profile.\n")
			return selected.Dir, nil
		}

		fmt.Fprintf(w, "Multiple Chrome profiles have cookies for %s:\n", domain)
		for i, p := range profiles {
			fmt.Fprintf(w, "  %d. %s (%s, %d %s)\n", i+1, p.DisplayName, p.Dir, profileCookieCount(p, required), label)
		}
		fmt.Fprintf(w, "Which profile? [1]: ")

		scanner := bufio.NewScanner(r)
		choice := 1
		if scanner.Scan() {
			text := strings.TrimSpace(scanner.Text())
			if text != "" {
				fmt.Sscanf(text, "%d", &choice)
			}
		}
		if choice < 1 || choice > len(profiles) {
			choice = 1
		}
		selected := profiles[choice-1]
		fmt.Fprintf(w, "Using profile: %s (%s)\n", selected.DisplayName, selected.Dir)
		return selected.Dir, nil
	}
}

func profileCookieCount(profile chromeProfile, required bool) int {
	if required {
		return profile.RequiredCookieCount
	}
	return profile.CookieCount
}

// resolveProfileByName finds a Chrome profile directory by its display name.
func resolveProfileByName(name string) (string, error) {
	dataDir, err := chromeDataDir()
	if err != nil {
		return "", err
	}

	entries, err := os.ReadDir(dataDir)
	if err != nil {
		return "", err
	}

	lowerName := strings.ToLower(name)
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dirName := entry.Name()
		if dirName != "Default" && !strings.HasPrefix(dirName, "Profile ") {
			continue
		}
		displayName := readProfileDisplayName(filepath.Join(dataDir, dirName, "Preferences"))
		if strings.ToLower(displayName) == lowerName || strings.ToLower(dirName) == lowerName {
			return dirName, nil
		}
	}

	return "", fmt.Errorf("Chrome profile %q not found", name)
}

// --- Cookie extraction tools ---

// resolvePythonBinary finds a usable Python 3 interpreter, returning the
// executable name and any leading args (e.g. `py -3` on Windows). pycookiecheat
// is the only tool the CLI shells into Python for, and Windows ships
// `python.exe` or the `py` launcher rather than `python3`.
func resolvePythonBinary() (string, []string, bool) {
	candidates := []struct {
		bin  string
		args []string
	}{
		{"python3", nil},
		{"python", nil},
		{"py", []string{"-3"}},
	}
	for _, c := range candidates {
		if _, err := exec.LookPath(c.bin); err == nil {
			return c.bin, c.args, true
		}
	}
	return "", nil, false
}

// cookieTool bundles the detected tool name with any auxiliary invocation
// data the extraction call needs. For pycookiecheat we carry the Python
// binary and its leading args so detection and extraction cannot disagree
// if PATH mutates between calls.
type cookieTool struct {
	name   string
	pyBin  string
	pyArgs []string
}

// tryPressAuth shells out to `press-auth cookies <domain>` and returns the
// resulting Cookie header value. Stderr from press-auth (if any) is surfaced
// as the error message so callers can include the recovery hint.
func tryPressAuth(pressAuthPath, domain string) (string, error) {
	cmd := exec.Command(pressAuthPath, "cookies", domain)
	var out, errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf
	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errBuf.String())
		if msg != "" {
			return "", fmt.Errorf("%s", msg)
		}
		return "", err
	}
	return strings.TrimSpace(out.String()), nil
}

func runCookieToolProbe(name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = io.Discard
	cmd.Stderr = io.Discard
	return cmd.Run()
}

// detectCookieTool checks for available cookie extraction tools in preference order.
// pycookiecheat is skipped on Windows because upstream raises
// `OSError("This script only works on MacOS or Linux.")` regardless of whether
// the import probe succeeds.
func detectCookieTool() (cookieTool, error) {
	if runtime.GOOS != "windows" {
		if bin, args, ok := resolvePythonBinary(); ok {
			probeArgs := append(append([]string{}, args...), "-c", "import pycookiecheat")
			if err := runCookieToolProbe(bin, probeArgs...); err == nil {
				return cookieTool{name: "pycookiecheat", pyBin: bin, pyArgs: args}, nil
			}
		}
		if path, err := exec.LookPath("pycookiecheat"); err == nil {
			if err := runCookieToolProbe(path, "--help"); err == nil {
				return cookieTool{name: "pycookiecheat-cli", pyBin: path}, nil
			}
		}
	}
	if err := runCookieToolProbe("cookies", "--help"); err == nil {
		return cookieTool{name: "cookies"}, nil
	}
	if err := runCookieToolProbe("cookie-scoop", "--help"); err == nil {
		return cookieTool{name: "cookie-scoop"}, nil
	}
	if runtime.GOOS == "windows" {
		return cookieTool{}, fmt.Errorf("no cookie extraction tool found; pycookiecheat does not support Windows. Use `auth login --browser` (live Chrome via CDP) or install cookie-scoop-cli")
	}
	return cookieTool{}, fmt.Errorf("no cookie extraction tool found; install one: pip install pycookiecheat")
}

// extractCookies shells out to the detected tool and returns a Cookie header value string.
// profileDir selects which Chrome profile to read from (e.g. "Default", "Profile 1").
func extractCookies(tool cookieTool, domain, profileDir string) (string, error) {
	switch tool.name {
	case "pycookiecheat":
		return extractViaPycookiecheat(tool, domain, profileDir)
	case "pycookiecheat-cli":
		return extractViaPycookiecheatCLI(tool, domain, profileDir)
	case "cookies":
		return extractViaCookiesCLI(domain)
	case "cookie-scoop":
		return extractViaCookieScoop(domain, profileDir)
	default:
		return "", fmt.Errorf("unknown cookie tool: %s", tool.name)
	}
}

func extractViaPycookiecheat(tool cookieTool, domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	cookiePath := ""
	if profileDir != "" {
		dataDir, err := chromeDataDir()
		if err == nil {
			cookiePath = filepath.Join(dataDir, profileDir, "Cookies")
		}
	}

	var script string
	if cookiePath != "" {
		// Use forward slashes so Python doesn't interpret backslashes as escapes on Windows
		safePath := filepath.ToSlash(cookiePath)
		script = fmt.Sprintf(
			`import json; from pycookiecheat import chrome_cookies; print(json.dumps(chrome_cookies("https://%s", cookie_file="%s")))`,
			cleanDomain, safePath,
		)
	} else {
		script = fmt.Sprintf(
			`import json; from pycookiecheat import chrome_cookies; print(json.dumps(chrome_cookies("https://%s")))`,
			cleanDomain,
		)
	}

	var out bytes.Buffer
	cmd := exec.Command(tool.pyBin, append(append([]string{}, tool.pyArgs...), "-c", script)...)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("pycookiecheat failed: %w", err)
	}

	var cookies map[string]string
	if err := json.Unmarshal(out.Bytes(), &cookies); err != nil {
		return "", fmt.Errorf("parsing pycookiecheat output: %w", err)
	}

	var parts []string
	for name, value := range cookies {
		parts = append(parts, name+"="+value)
	}
	return strings.Join(parts, "; "), nil
}

func extractViaPycookiecheatCLI(tool cookieTool, domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	var args []string
	if profileDir != "" {
		dataDir, err := chromeDataDir()
		if err != nil {
			return "", err
		}
		args = append(args, "-c", filepath.Join(dataDir, profileDir, "Cookies"))
	}
	args = append(args, "https://"+cleanDomain)

	var out bytes.Buffer
	cmd := exec.Command(tool.pyBin, args...)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("pycookiecheat cli failed: %w", err)
	}

	var cookies map[string]string
	if err := json.Unmarshal(out.Bytes(), &cookies); err != nil {
		return "", fmt.Errorf("parsing pycookiecheat output: %w", err)
	}

	var parts []string
	for name, value := range cookies {
		parts = append(parts, name+"="+value)
	}
	return strings.Join(parts, "; "), nil
}

func extractViaCookiesCLI(domain string) (string, error) {
	// barnardb/cookies doesn't support profile selection — reads Default
	var out bytes.Buffer
	cmd := exec.Command("cookies", "https://"+strings.TrimPrefix(domain, "."))
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("cookies cli failed: %w", err)
	}

	result := strings.TrimSpace(out.String())
	result = strings.TrimPrefix(result, "Cookie: ")
	return result, nil
}

// parseCookieString splits a "name1=value1; name2=value2" string into a map.
func parseCookieString(cookies string) map[string]string {
	m := make(map[string]string)
	for _, pair := range strings.Split(cookies, ";") {
		pair = strings.TrimSpace(pair)
		if pair == "" {
			continue
		}
		idx := strings.IndexByte(pair, '=')
		if idx < 0 {
			continue
		}
		name := strings.TrimSpace(pair[:idx])
		if name == "" {
			continue
		}
		m[name] = strings.TrimSpace(pair[idx+1:])
	}
	return m
}

func extractViaCookieScoop(domain, profileDir string) (string, error) {
	cleanDomain := strings.TrimPrefix(domain, ".")
	args := []string{"--url", "https://" + cleanDomain, "--header"}
	if profileDir != "" {
		args = append(args, "--chrome-profile", profileDir)
	}

	var out bytes.Buffer
	cmd := exec.Command("cookie-scoop", args...)
	cmd.Stdout = &out
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		return "", fmt.Errorf("cookie-scoop failed: %w", err)
	}

	result := strings.TrimSpace(out.String())
	result = strings.TrimPrefix(result, "Cookie: ")
	return result, nil
}

// validateComposedAuth makes a lightweight test request to verify the session is still active.
// Uses the API base URL — any authenticated endpoint returning 401/403 indicates expiry.
// A non-auth error (404, 500, timeout) is treated as "can't validate, assume OK" to avoid
// blocking auth on unrelated API issues.
func validateComposedAuth(authHeader string) error {
	testURL := "https://members.erank.com"
	req, err := http.NewRequest("HEAD", testURL, nil)
	if err != nil {
		return nil // can't validate, assume OK
	}
	req.Header.Set("X-XSRF-TOKEN", authHeader)

	client := &http.Client{Timeout: 5 * time.Second}
	resp, err := client.Do(req)
	if err != nil {
		return nil // network error, assume OK — don't block auth on connectivity
	}
	defer resp.Body.Close()

	if resp.StatusCode == 401 || resp.StatusCode == 403 {
		return fmt.Errorf("HTTP %d", resp.StatusCode)
	}
	return nil
}

type browserSessionProof struct {
	APIName               string `json:"api_name"`
	CookieDomain          string `json:"cookie_domain"`
	ValidationMethod      string `json:"validation_method"`
	ValidationPath        string `json:"validation_path"`
	StatusCode            int    `json:"status_code"`
	AuthSource            string `json:"auth_source"`
	CredentialFingerprint string `json:"credential_fingerprint"`
	VerifiedAt            string `json:"verified_at"`
}

func browserSessionProofPath(cfg *config.Config) string {
	if cfg == nil || cfg.Path == "" {
		home, _ := os.UserHomeDir()
		return filepath.Join(home, ".config", "erank-pp-cli", "browser-session-proof.json")
	}
	return filepath.Join(filepath.Dir(cfg.Path), "browser-session-proof.json")
}

func clearBrowserSessionProof(cfg *config.Config) error {
	proofPath := browserSessionProofPath(cfg)
	if err := os.Remove(proofPath); err != nil && !errors.Is(err, os.ErrNotExist) {
		return err
	}
	return nil
}

func writeBrowserSessionProof(cfg *config.Config, data []byte) error {
	proofPath := browserSessionProofPath(cfg)
	if err := os.MkdirAll(filepath.Dir(proofPath), 0o700); err != nil {
		return fmt.Errorf("creating proof directory: %w", err)
	}
	tmpPath := proofPath + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
		return fmt.Errorf("writing temporary proof: %w", err)
	}
	if err := os.Rename(tmpPath, proofPath); err != nil {
		_ = os.Remove(tmpPath)
		return fmt.Errorf("publishing proof: %w", err)
	}
	return nil
}

func browserSessionProofStatusForAuth(cfg *config.Config, authHeader string) (bool, string) {
	if cfg == nil {
		return false, "config unavailable"
	}
	if authHeader == "" {
		return false, "no browser session credentials configured"
	}
	data, err := os.ReadFile(browserSessionProofPath(cfg))
	if err != nil {
		return false, "proof not found; run erank-pp-cli auth login --chrome"
	}
	var proof browserSessionProof
	if err := json.Unmarshal(data, &proof); err != nil {
		return false, "proof is not valid JSON; re-run erank-pp-cli auth login --chrome"
	}
	if proof.APIName != "erank" || proof.CookieDomain != "members.erank.com" || proof.ValidationPath != "/api/keyword-tool/stats?keyword=dad+mug&country=USA&marketplace=etsy" {
		return false, "proof does not match this CLI"
	}
	if authHeader != "" && proof.CredentialFingerprint != fingerprintCredential(authHeader) {
		return false, "proof does not match the currently configured browser session"
	}
	if proof.StatusCode < 200 || proof.StatusCode >= 300 {
		return false, fmt.Sprintf("proof recorded HTTP %d", proof.StatusCode)
	}
	return true, fmt.Sprintf("%s %s verified at %s", proof.ValidationMethod, proof.ValidationPath, proof.VerifiedAt)
}

func validateAndWriteBrowserSessionProof(ctx context.Context, cfg *config.Config, flags *rootFlags) error {
	validationPath := strings.TrimSpace("/api/keyword-tool/stats?keyword=dad+mug&country=USA&marketplace=etsy")
	if validationPath == "" {
		return fmt.Errorf("no browser-session validation endpoint configured in this CLI")
	}
	method := strings.ToUpper(strings.TrimSpace("GET"))
	if method == "" {
		method = "GET"
	}
	if method != "GET" {
		return fmt.Errorf("browser-session validation only supports GET endpoints for now (got %s)", method)
	}

	authHeader := cfg.AuthHeader()
	if authHeader == "" {
		return fmt.Errorf("no browser session credentials were saved")
	}

	c := client.New(cfg, flags.timeout, flags.rateLimit)
	c.NoCache = true
	status, err := c.ProbeGet(ctx, validationPath)
	if err != nil {
		return err
	}
	if status < 200 || status >= 300 {
		return fmt.Errorf("validation endpoint returned HTTP %d", status)
	}

	proof := browserSessionProof{
		APIName:               "erank",
		CookieDomain:          "members.erank.com",
		ValidationMethod:      method,
		ValidationPath:        validationPath,
		StatusCode:            status,
		AuthSource:            browserSessionAuthSource(cfg, authHeader),
		CredentialFingerprint: fingerprintCredential(authHeader),
		VerifiedAt:            time.Now().UTC().Format(time.RFC3339),
	}

	data, err := json.MarshalIndent(proof, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling proof: %w", err)
	}
	data = append(data, '\n')
	return writeBrowserSessionProof(cfg, data)
}

func validateAndWriteBrowserSessionProofWithRetry(ctx context.Context, cfg *config.Config, flags *rootFlags, timeout time.Duration) error {
	deadline := time.Now().Add(timeout)
	var lastErr error
	for {
		if err := validateAndWriteBrowserSessionProof(ctx, cfg, flags); err != nil {
			lastErr = err
		} else {
			return nil
		}
		if time.Now().After(deadline) {
			return lastErr
		}
		timer := time.NewTimer(time.Second)
		select {
		case <-ctx.Done():
			timer.Stop()
			return ctx.Err()
		case <-timer.C:
		}
	}
}

func fingerprintCredential(value string) string {
	sum := sha256.Sum256([]byte(value))
	return hex.EncodeToString(sum[:8])
}

func browserSessionAuthSource(cfg *config.Config, authHeader string) string {
	if authHeader == "" {
		return "browser"
	}
	if cfg != nil && cfg.AuthSource != "" {
		return cfg.AuthSource
	}
	return "browser"
}

// --- Live browser cookie extraction (session cookies fallback) ---

// extractLiveCookies reads document.cookie from a live Chrome session.
// Tries: agent-browser → browser-use → raw CDP, in that order.
func extractLiveCookies(domain string) (string, error) {
	targetURL := "https://" + strings.TrimPrefix(domain, ".")

	// 1. Try browser-use --connect (preferred — has full DOM/cookie access)
	if _, err := exec.LookPath("browser-use"); err == nil {
		cookies, err := extractViaBrowserUse(targetURL)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	// 2. Try agent-browser --auto-connect (fallback — limited eval in auto-connect mode)
	if _, err := exec.LookPath("agent-browser"); err == nil {
		cookies, err := extractViaAgentBrowser(targetURL)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	// 3. Try raw CDP on common debug ports
	for _, port := range []string{"9222", "9229"} {
		cookies, err := extractViaCDP(targetURL, port)
		if err == nil && cookies != "" {
			return cookies, nil
		}
	}

	return "", fmt.Errorf("no live browser connection available (tried agent-browser, browser-use, CDP)")
}

func extractViaAgentBrowser(targetURL string) (string, error) {
	// Open the target URL (attaches to running Chrome)
	openCmd := exec.Command("agent-browser", "--auto-connect", "open", targetURL)
	openCmd.Stderr = os.Stderr
	if err := openCmd.Run(); err != nil {
		return "", fmt.Errorf("agent-browser open: %w", err)
	}

	// Read document.cookie via eval
	var out bytes.Buffer
	evalCmd := exec.Command("agent-browser", "eval", "document.cookie")
	evalCmd.Stdout = &out
	evalCmd.Stderr = os.Stderr
	if err := evalCmd.Run(); err != nil {
		closeCmd := exec.Command("agent-browser", "close")
		_ = closeCmd.Run()
		return "", fmt.Errorf("agent-browser eval: %w", err)
	}

	// Close the daemon
	closeCmd := exec.Command("agent-browser", "close")
	_ = closeCmd.Run()

	return strings.TrimSpace(out.String()), nil
}

func extractViaBrowserUse(targetURL string) (string, error) {
	// Try connecting to running Chrome
	openCmd := exec.Command("browser-use", "--connect", "open", targetURL)
	openCmd.Stderr = os.Stderr
	if err := openCmd.Run(); err != nil {
		return "", fmt.Errorf("browser-use open: %w", err)
	}

	var out bytes.Buffer
	evalCmd := exec.Command("browser-use", "eval", "document.cookie")
	evalCmd.Stdout = &out
	evalCmd.Stderr = os.Stderr
	if err := evalCmd.Run(); err != nil {
		closeCmd := exec.Command("browser-use", "close")
		_ = closeCmd.Run()
		return "", fmt.Errorf("browser-use eval: %w", err)
	}

	closeCmd := exec.Command("browser-use", "close")
	_ = closeCmd.Run()

	result := strings.TrimSpace(out.String())
	// browser-use eval prefixes with "result: "
	result = strings.TrimPrefix(result, "result: ")
	return result, nil
}

func extractViaCDP(targetURL, port string) (string, error) {
	// Discover available tabs via CDP JSON endpoint
	listURL := fmt.Sprintf("http://localhost:%s/json", port)
	client := &http.Client{Timeout: 2 * time.Second}
	resp, err := client.Get(listURL)
	if err != nil {
		return "", fmt.Errorf("CDP not available on port %s", port)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}

	// Find a tab matching the target domain
	domain := strings.TrimPrefix(strings.TrimPrefix(targetURL, "https://"), "http://")
	var tabs []struct {
		URL                  string `json:"url"`
		WebSocketDebuggerURL string `json:"webSocketDebuggerUrl"`
	}
	if err := json.Unmarshal(body, &tabs); err != nil {
		return "", fmt.Errorf("parsing CDP tabs: %w", err)
	}

	var wsURL string
	for _, tab := range tabs {
		if strings.Contains(tab.URL, domain) {
			wsURL = tab.WebSocketDebuggerURL
			break
		}
	}
	if wsURL == "" {
		return "", fmt.Errorf("no Chrome tab found for %s", domain)
	}

	return evalDocumentCookieViaCDP(wsURL, domain)
}

// evalDocumentCookieViaCDP opens the per-tab DevTools WebSocket and runs a
// single Runtime.evaluate of `document.cookie`. Bounded by a single 5-second
// wall-clock deadline shared across the dial, write, and all subsequent frame
// reads — net.Conn.SetReadDeadline is a single deadline covering all reads on
// the connection, not a per-message reset, so heavy CDP event traffic chips
// away at the same budget. Returns the cookie string verbatim (no parsing) so
// the existing extractLiveCookies pipeline can hand it to refreshStoredBrowserCookies.
func evalDocumentCookieViaCDP(wsURL, domain string) (string, error) {
	dialer := websocket.Dialer{HandshakeTimeout: 2 * time.Second}
	conn, _, err := dialer.Dial(wsURL, nil)
	if err != nil {
		return "", fmt.Errorf("CDP WebSocket dial failed for %s: %w", domain, err)
	}
	defer conn.Close()

	deadline := time.Now().Add(5 * time.Second)
	_ = conn.SetWriteDeadline(deadline)
	_ = conn.SetReadDeadline(deadline)

	const evalID = 1
	evalReq := map[string]any{
		"id":     evalID,
		"method": "Runtime.evaluate",
		"params": map[string]any{
			"expression":    "document.cookie",
			"returnByValue": true,
			"awaitPromise":  true,
		},
	}
	if err := conn.WriteJSON(evalReq); err != nil {
		return "", fmt.Errorf("CDP Runtime.evaluate write failed for %s: %w", domain, err)
	}

	// Drain frames until we see our response. CDP can interleave events from
	// other domains (Network, Page) on the same socket if those domains were
	// enabled in this tab by another client; ignore them and keep reading
	// until the shared 5-second deadline above fires. Heavy event traffic can
	// exhaust the budget before our response arrives — that's by design (a
	// stuck tab fails fast) rather than a per-read timeout.
	for {
		var msg struct {
			ID     int             `json:"id"`
			Result json.RawMessage `json:"result"`
			Error  *struct {
				Code    int    `json:"code"`
				Message string `json:"message"`
			} `json:"error"`
		}
		if err := conn.ReadJSON(&msg); err != nil {
			return "", fmt.Errorf("CDP Runtime.evaluate read failed for %s: %w", domain, err)
		}
		if msg.ID != evalID {
			continue
		}
		if msg.Error != nil {
			return "", fmt.Errorf("CDP Runtime.evaluate error for %s: %s", domain, msg.Error.Message)
		}
		var result struct {
			Result struct {
				Type  string `json:"type"`
				Value string `json:"value"`
			} `json:"result"`
			ExceptionDetails *struct {
				Text string `json:"text"`
			} `json:"exceptionDetails"`
		}
		if err := json.Unmarshal(msg.Result, &result); err != nil {
			return "", fmt.Errorf("CDP Runtime.evaluate result parse failed for %s: %w", domain, err)
		}
		if result.ExceptionDetails != nil {
			return "", fmt.Errorf("CDP page threw evaluating document.cookie for %s: %s", domain, result.ExceptionDetails.Text)
		}
		return result.Result.Value, nil
	}
}
